namespace sv_bbe56965aea24b289ed9f5f9b220f91b.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_bbe56965aea24b289ed9f5f9b220f91b.Components.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel.Id);
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    border-radius: 10px;
    padding: 1px 7px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@namespace sv_bbe56965aea24b289ed9f5f9b220f91b.Components.Chat

<div class="channel-list">
    <div class="channel-list-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list-items">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2c2f33;
    color: #dcddde;
    overflow: hidden;
}

.channel-list-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.channel-list-header h5 {
    margin: 0;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
}

.channel-list-items {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

@namespace sv_bbe56965aea24b289ed9f5f9b220f91b.Components.Chat

<div class="message-input">
    <textarea @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="1"></textarea>
    <button class="send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = string.Empty;
        await OnSubmit.InvokeAsync(message);
    }
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    background-color: #40444b;
    border-radius: 8px;
    margin: 0 16px 16px;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    background: transparent;
    border: none;
    outline: none;
    color: #dcddde;
    font-size: 0.9rem;
    resize: none;
    font-family: inherit;
    max-height: 120px;
}

.message-input textarea::placeholder {
    color: #72767d;
}

.send-btn {
    background-color: #5865f2;
    color: #fff;
    border: none;
    border-radius: 4px;
    padding: 6px 16px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background-color: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

