    flex-shrink: 0;
}

.area-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.area-description {
    font-size: 0.8rem;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    font-size: 0.8rem;
    color: #72767d;
}

