toolArgs.file_text:
@namespace sv_bbe56965aea24b289ed9f5f9b220f91b.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="thread-root-author">@RootMessage.Author</div>
            <div class="thread-root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-avatar">@reply.Author[0]</div>
                    <div class="reply-body">
                        <div class="reply-meta">
                            <span class="reply-author">@reply.Author</span>
                            <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="reply-content">@reply.Content</div>
                    </div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply…"
                      ButtonLabel="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #36393f;
    border-left: 1px solid rgba(0, 0, 0, 0.25);
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid rgba(0, 0, 0, 0.2);
    flex-shrink: 0;
}

.thread-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #8e9297;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s, color 0.1s;
}

.close-btn:hover {
    background-color: rgba(255, 255, 255, 0.08);
    color: #fff;
}

.thread-root {
    padding: 12px 16px;
    background-color: rgba(0, 0, 0, 0.1);
    border-bottom: 1px solid rgba(0, 0, 0, 0.15);
    flex-shrink: 0;
}

.thread-root-author {
    font-weight: 600;
    font-size: 0.85rem;
    color: #fff;
    margin-bottom: 4px;
}

.thread-root-content {
    font-size: 0.85rem;
    color: #b9bbbe;
    line-height: 1.4;
}

.thread-divider {
    padding: 8px 16px;
    text-align: center;
    flex-shrink: 0;
}

.thread-divider span {
    font-size: 0.75rem;
    color: #72767d;
    background-color: #36393f;
    padding: 0 8px;
    position: relative;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    display: flex;
    gap: 10px;
    padding: 6px 16px;
}

.thread-reply:hover {
    background-color: rgba(0, 0, 0, 0.06);
}

.reply-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background-color: #5865f2;
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 0.75rem;
    flex-shrink: 0;
    text-transform: uppercase;
}

.reply-body {
    flex: 1;
    min-width: 0;
}

.reply-meta {
    display: flex;
    align-items: baseline;
    gap: 6px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 600;
    font-size: 0.82rem;
    color: #fff;
}

.reply-time {
    font-size: 0.7rem;
    color: #72767d;
}

.reply-content {
    font-size: 0.85rem;
    color: #dcddde;
    line-height: 1.3;
    word-break: break-word;
}

