@page "/chat"
@using sv_bbe56965aea24b289ed9f5f9b220f91b.Components.Chat
@using sv_bbe56965aea24b289ed9f5f9b220f91b.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelList Channels="_channels"
                     ActiveChannelId="_activeChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <MessageArea ChannelName="@_activeChannel.Name"
                         ChannelDescription="@_activeChannel.Description"
                         Messages="_messages"
                         ThreadReplyCounts="_threadReplyCounts"
                         HasMoreMessages="_hasMoreMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReact="AddReaction"
                         OnLoadMore="LoadMoreMessages" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         ThreadMessages="_threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 50;

    private List<Channel> _channels = [];
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private bool _hasMoreMessages = true;

    private bool _threadOpen;
    private int _threadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _hasMoreMessages = true;
        _threadOpen = false;

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count >= PageSize;

        await ChatService.MarkChannelReadAsync(channelId);
        await ComputeThreadCounts();

        // Refresh unread count in sidebar
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (!_hasMoreMessages || _activeChannel is null) return;

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _messages.Count, PageSize);
        if (older.Count < PageSize)
        {
            _hasMoreMessages = false;
        }
        _messages.InsertRange(0, older);
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(sent);
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private async Task CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
        // Refresh thread counts since user may have added replies
        await ComputeThreadCounts();
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootId);
        _threadMessages.Add(reply);

        // Update reply count in main area
        _threadReplyCounts[_threadRootId] = _threadMessages.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Refresh messages to show updated reactions
        if (_activeChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId, 0, _messages.Count);
            _messages = refreshed;
        }
    }

    private async Task ComputeThreadCounts()
    {
        _threadReplyCounts = [];
        // Identify thread starters: messages that have replies pointing to them
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(rootId);
                if (thread.Count > 0)
                {
                    _threadReplyCounts[rootId] = thread.Count;
                }
            }
            catch
            {
                // Thread may not exist yet
            }
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    background-color: #36393f;
    color: #dcddde;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.chat-main.expanded {
    /* Takes remaining space when thread panel is closed */
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.no-channel {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #72767d;
    font-size: 1.1rem;
}

